def ceil_search(arr, low, high, x):
    """
    Searches for the smallest element in arr[low...high] which is greater than or equal to x.
    This function assumes that the input array is sorted.
    """
    # Base cases
    # If x is smaller than or equal to the first element, then the first element is the ceiling
    if x <= arr[low]:
        return low
    # If x is greater than the last element, then the ceiling doesn't exist in the array
    if x > arr[high]:
        return -1
    # Find the middle point
    mid = (low + high) // 2
    # If x is same as middle element, then middle element is the ceiling
    if arr[mid] == x:
        return mid
    # If x is greater than arr[mid], then either arr[mid + 1] is the ceiling
    # or the ceiling lies in arr[mid+1...high]
    elif arr[mid] < x:
        if mid + 1 <= high and x <= arr[mid + 1]:
            return mid + 1
        else:
            return ceil_search(arr, mid + 1, high, x)
    # If x is smaller than arr[mid], then either arr[mid] is the ceiling
    # or the ceiling lies in arr[low...mid-1]
    else:
        if mid - 1 >= low and x > arr[mid - 1]:
            return mid
        else:
            return ceil_search(arr, low, mid - 1, x)

