def lbs(arr):
    """
    This function finds the length of the Longest Bitonic Subsequence in an array.
    A bitonic subsequence is a subsequence which is first increasing and then decreasing.
    """
    n = len(arr)
    if n == 0:
        return 0
    # lis[i] stores the length of the Longest Increasing Subsequence ending at arr[i]
    lis = [1] * n
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j] and lis[i] < lis[j] + 1:
                lis[i] = lis[j] + 1
    # lds[i] stores the length of the Longest Decreasing Subsequence starting at arr[i]
    lds = [1] * n
    # Note the reverse iteration
    for i in range(n - 2, -1, -1):
        for j in range(n - 1, i, -1):
            if arr[i] > arr[j] and lds[i] < lds[j] + 1:
                lds[i] = lds[j] + 1
    # Find the maximum value of lis[i] + lds[i] - 1
    # The peak element arr[i] is counted in both LIS and LDS, so we subtract 1.
    max_len = 0
    for i in range(n):
        current_len = lis[i] + lds[i] - 1
        if current_len > max_len:
            max_len = current_len
    return max_len

