def is_product(arr, n, x):
  """
  Checks if a pair of distinct elements in the array exists whose product is equal to x.
  Args:
    arr: A list of integers.
    n: The number of elements in the array.
    x: The target product.
  Returns:
    True if such a pair exists, False otherwise.
  """
  hset = set()
  if n < 2:
    return False
  for i in range(n):
    # Handle the case where the current element is 0
    if arr[i] == 0:
      if x == 0:
        return True  # Found a pair (0 * any_other_number)
      else:
        continue  # 0 cannot be a factor of a non-zero x
    # If the current element is a divisor of x
    if x % arr[i] == 0:
      # Check if the complementary factor is already in the set
      if x // arr[i] in hset:
        return True
      # Add the current element to the set for future checks
      hset.add(arr[i])
  return False

