def search(arr, l, h, key):
  """
  Searches for a key in a rotated sorted array.
  Args:
    arr: The rotated sorted list of integers.
    l: The starting index of the search range.
    h: The ending index of the search range.
    key: The integer to search for.
  Returns:
    The index of the key if found, otherwise -1.
  """
  if l > h:
    return -1
  mid = (l + h) // 2
  if arr[mid] == key:
    return mid
  # If arr[l...mid] is sorted
  if arr[l] <= arr[mid]:
    # As this subarray is sorted, we can check if key lies in this half
    if key >= arr[l] and key <= arr[mid]:
      return search(arr, l, mid - 1, key)
    # If key does not lie in this half, then it must be in the other half
    return search(arr, mid + 1, h, key)
  # If arr[l...mid] is not sorted, then arr[mid...h] must be sorted
  if key >= arr[mid] and key <= arr[h]:
    return search(arr, mid + 1, h, key)
  return search(arr, l, mid - 1, key)

