def gcd(a, b):
  """
  Calculates the greatest common divisor of two integers using the binary GCD algorithm.
  """
  if a == b:
    return a
  if a == 0:
    return b
  if b == 0:
    return a
  # The Java expression `(~a & 1) == 1` checks if 'a' is even.
  # A more idiomatic Python equivalent is `not (a & 1)`.
  # a is even
  if not (a & 1):
    # b is odd
    if b & 1:
      return gcd(a >> 1, b)
    # b is also even
    else:
      return gcd(a >> 1, b >> 1) << 1
  # a is odd, b is even
  if not (b & 1):
    return gcd(a, b >> 1)
  # Both a and b are odd
  if a > b:
    return gcd((a - b) >> 1, b)
  return gcd((b - a) >> 1, a)

