def binomial_coeff_sum(n):
  C = [[0] * (n + 1) for _ in range(n + 1)]
  # Calculate binomial coefficients using Pascal's identity
  for i in range(n + 1):
    # The original Java code's `Math.min(i, n)` is equivalent to `i`
    # because the outer loop ensures `i` is always less than or equal to `n`.
    for j in range(i + 1):
      # Base cases
      if j == 0 or j == i:
        C[i][j] = 1
      # Recursive step
      else:
        C[i][j] = C[i - 1][j - 1] + C[i - 1][j]
  # Sum the coefficients of the nth row
  total_sum = 0
  for i in range(n + 1):
    total_sum += C[n][i]
  return total_sum

