def count_ways(n):
    table = [0] * (n + 1)
    table[0] = 1
    # This problem is equivalent to finding the number of partitions of n
    # into parts smaller than n.
    for i in range(1, n):
        for j in range(i, n + 1):
            table[j] += table[j - i]
    return table[n]

